  1→/**
  2→ * Graph scan: periodic workspace-wide analysis for contradictions and anomalies.
  3→ *
  4→ * Pure query functions that gather scan signals from the workspace graph,
  5→ * then delegate to the observer agent for contradiction analysis.
  6→ *
  7→ * Scan types:
  8→ *   1. Decision-implementation contradictions: confirmed decisions vs completed tasks
  9→ *   2. Stale blocked tasks: tasks blocked longer than threshold (14 days)
 10→ */
 11→
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import type { LanguageModel } from "ai";
 14→import { createObservation, listWorkspaceOpenObservations, type ObserveTargetRecord } from "../observation/queries";
 15→import { logInfo } from "../http/observability";
 16→import { synthesizePatterns, type Anomaly } from "./llm-synthesis";
 17→import { parseEntityRef } from "./evidence-validator";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Types
 21→// ---------------------------------------------------------------------------
 22→
 23→export type ConfirmedDecision = {
 24→  id: RecordId<"decision">;
 25→  summary: string;
 26→  rationale?: string;
 27→};
 28→
 29→export type CompletedTask = {
 30→  id: RecordId<"task">;
 31→  title: string;
 32→  description?: string;
 33→};
 34→
 35→export type StaleBlockedTask = {
 36→  id: RecordId<"task">;
 37→  title: string;
 38→  description?: string;
 39→  updated_at: string | Date;
 40→  daysBlocked: number;
 41→};
 42→
 43→export type StatusDriftTask = {
 44→  id: RecordId<"task">;
 45→  title: string;
 46→  status: string;
 47→  dependency: {
 48→    id: RecordId<"task">;
 49→    title: string;
 50→    status: string;
 51→  };
 52→};
 53→
 54→export type GraphScanResult = {
 55→  contradictions_found: number;
 56→  stale_blocked_found: number;
 57→  status_drift_found: number;
 58→  observations_created: number;
 59→};
 60→
 61→// ---------------------------------------------------------------------------
 62→// Configuration
 63→// ---------------------------------------------------------------------------
 64→
 65→const STALE_BLOCKED_THRESHOLD_DAYS = 14;
 66→
 67→// ---------------------------------------------------------------------------
 68→// Graph queries (pure data gathering)
 69→// ---------------------------------------------------------------------------
 70→
 71→async function queryConfirmedDecisions(
 72→  surreal: Surreal,
 73→  workspaceRecord: RecordId<"workspace", string>,
 74→): Promise<ConfirmedDecision[]> {
 75→  const [rows] = await surreal.query<[ConfirmedDecision[]]>(
 76→    `SELECT id, summary, rationale, created_at FROM decision
 77→     WHERE workspace = $ws AND status = "confirmed"
 78→     ORDER BY created_at DESC
 79→     LIMIT 50;`,
 80→    { ws: workspaceRecord },
 81→  );
 82→  return rows ?? [];
 83→}
 84→
 85→async function queryCompletedTasks(
 86→  surreal: Surreal,
 87→  workspaceRecord: RecordId<"workspace", string>,
 88→): Promise<CompletedTask[]> {
 89→  const [rows] = await surreal.query<[CompletedTask[]]>(
 90→    `SELECT id, title, description, updated_at FROM task
 91→     WHERE workspace = $ws AND status IN ["completed", "done"]
 92→     ORDER BY updated_at DESC
 93→     LIMIT 50;`,
 94→    { ws: workspaceRecord },
 95→  );
 96→  return rows ?? [];
 97→}
 98→
 99→async function queryStaleBlockedTasks(
100→  surreal: Surreal,
101→  workspaceRecord: RecordId<"workspace", string>,
102→): Promise<StaleBlockedTask[]> {
103→  const thresholdDate = new Date(
104→    Date.now() - STALE_BLOCKED_THRESHOLD_DAYS * 24 * 60 * 60 * 1000,
105→  );
106→
107→  const [rows] = await surreal.query<
108→    [Array<{ id: RecordId<"task">; title: string; description?: string; updated_at: string }>]
109→  >(
110→    `SELECT id, title, description, updated_at FROM task
111→     WHERE workspace = $ws
112→       AND status = "blocked"
113→       AND updated_at < $threshold
114→     ORDER BY updated_at ASC
115→     LIMIT 50;`,
116→    { ws: workspaceRecord, threshold: thresholdDate },
117→  );
118→
119→  return (rows ?? []).map((row) => {
120→    const updatedAt = new Date(row.updated_at);
121→    const daysBlocked = Math.floor(
122→      (Date.now() - updatedAt.getTime()) / (24 * 60 * 60 * 1000),
123→    );
124→    return { ...row, daysBlocked };
125→  });
126→}
127→
128→async function queryStatusDriftTasks(
129→  surreal: Surreal,
130→  workspaceRecord: RecordId<"workspace", string>,
131→): Promise<StatusDriftTask[]> {
132→  // Two-step approach: first find completed tasks with dependencies,
133→  // then filter for incomplete dependencies in application code
134→  const [rows] = await surreal.query<[Array<{
135→    id: RecordId<"task">;
136→    title: string;
137→    status: string;
138→    dep_ids: RecordId<"task">[];
139→    dep_titles: string[];
140→    dep_statuses: string[];
141→  }>]>(
142→    `SELECT
143→       id, title, status,
144→       ->depends_on->task.id AS dep_ids,
145→       ->depends_on->task.title AS dep_titles,
146→       ->depends_on->task.status AS dep_statuses
147→     FROM task
148→     WHERE workspace = $ws
149→       AND status IN ["completed", "done"]
150→       AND array::len(->depends_on->task) > 0
151→     LIMIT 50;`,
152→    { ws: workspaceRecord },
153→  );
154→
155→  return (rows ?? []).flatMap((row) => {
156→    const depIds = row.dep_ids ?? [];
157→    const depTitles = row.dep_titles ?? [];
158→    const depStatuses = row.dep_statuses ?? [];
159→
160→    const drifts: StatusDriftTask[] = [];
161→    for (let i = 0; i < depIds.length; i++) {
162→      const depStatus = depStatuses[i];
163→      if (depStatus !== "completed" && depStatus !== "done") {
164→        drifts.push({
165→          id: row.id,
166→          title: row.title,
167→          status: row.status,
168→          dependency: {
169→            id: depIds[i],
170→            title: depTitles[i],
171→            status: depStatus,
172→          },
173→        });
174→      }
175→    }
176→    return drifts;
177→  });
178→}
179→
180→// ---------------------------------------------------------------------------
181→// Entity-level deduplication query
182→// ---------------------------------------------------------------------------
183→
184→/**
185→ * Queries existing open observer observations linked to a specific entity.
186→ * Used for entity-level dedup -- if the observer already has an open observation
187→ * on this entity, we skip creating another.
188→ */
189→const ALLOWED_OBSERVER_TABLES = ["project", "feature", "task", "decision", "question", "intent", "git_commit", "observation"];
190→
191→async function queryExistingObserverObservationsForEntity(
192→  surreal: Surreal,
193→  workspaceRecord: RecordId<"workspace", string>,
194→  entityRecord: RecordId<string, string>,
195→): Promise<Array<{ text: string; severity: string; status: string }>> {
196→  if (!ALLOWED_OBSERVER_TABLES.includes(entityRecord.table.name)) {
197→    throw new Error(`Invalid entity table for observer dedup query: ${entityRecord.table.name}`);
198→  }
199→
200→  const [rows] = await surreal.query<[Array<{ text: string; severity: string; status: string }>]>(
201→    `SELECT text, severity, status FROM observation
202→     WHERE workspace = $ws
203→       AND source_agent = "observer_agent"
204→       AND status IN ["open", "acknowledged"]
205→       AND ->observes->${entityRecord.table.name}.id CONTAINS $entity
206→     LIMIT 20;`,
207→    { ws: workspaceRecord, entity: entityRecord },
208→  );
209→  return rows ?? [];
210→}
211→
212→// ---------------------------------------------------------------------------
213→// Contradiction detection (deterministic heuristic)
214→// ---------------------------------------------------------------------------
215→
216→/**
217→ * Simple keyword-based contradiction detection between decisions and tasks.
218→ * Looks for signals that a completed task contradicts a confirmed decision.
219→ *
220→ * Returns pairs of (decision, task) that appear contradictory.
221→ */
222→function detectContradictions(
223→  decisions: ConfirmedDecision[],
224→  tasks: CompletedTask[],
225→): Array<{ decision: ConfirmedDecision; task: CompletedTask }> {
226→  const contradictions: Array<{ decision: ConfirmedDecision; task: CompletedTask }> = [];
227→
228→  for (const decision of decisions) {
229→    const decisionText = decision.summary.toLowerCase();
230→
231→    for (const task of tasks) {
232→      const taskText = `${task.title} ${task.description ?? ""}`.toLowerCase();
233→
234→      // Detect technology contradictions
235→      // e.g., decision says "use tRPC" but task implements "REST" or "Express"
236→      if (detectsTechnologyContradiction(decisionText, taskText)) {
237→        contradictions.push({ decision, task });
238→      }
239→    }
240→  }
241→
242→  return contradictions;
243→}
244→
245→/**
246→ * Detects when a task uses a technology that contradicts a decision mandate.
247→ * Checks known technology pairs (e.g., tRPC vs REST, GraphQL vs REST).
248→ */
249→function detectsTechnologyContradiction(
250→  decisionText: string,
251→  taskText: string,
252→): boolean {
253→  const technologyPairs: Array<{ mandated: string[]; contradicting: string[] }> = [
254→    {
255→      mandated: ["trpc"],
256→      contradicting: ["rest", "express"],
257→    },
258→    {
259→      mandated: ["graphql"],
260→      contradicting: ["rest", "express"],
261→    },
262→    {
263→      mandated: ["typescript"],
264→      contradicting: ["javascript"],
265→    },
266→  ];
267→
268→  for (const pair of technologyPairs) {
269→    const mandatesThis = pair.mandated.some((term) => decisionText.includes(term));
270→    const taskUsesContradicting = pair.contradicting.some((term) => taskText.includes(term));
271→
272→    if (mandatesThis && taskUsesContradicting) {
273→      return true;
274→    }
275→  }
276→
277→  return false;
278→}
279→
280→// ---------------------------------------------------------------------------
281→// Deduplication
282→// ---------------------------------------------------------------------------
283→
284→type ExistingObservation = {
285→  text: string;
286→  severity: string;
287→  status: string;
288→};
289→
290→function isAlreadyObserved(
291→  existingObservations: ExistingObservation[],
292→  newText: string,
293→): boolean {
294→  const normalizedNew = newText.toLowerCase();
295→
296→  return existingObservations.some((obs) => {
297→    if (obs.status === "resolved") return false;
298→    const normalizedExisting = obs.text.toLowerCase();
299→    // Check if the core issue is already covered
300→    return (
301→      normalizedExisting.includes(normalizedNew.slice(0, 40)) ||
302→      normalizedNew.includes(normalizedExisting.slice(0, 40))
303→    );
304→  });
305→}
306→
307→// ---------------------------------------------------------------------------
308→// Scan orchestrator
309→// ---------------------------------------------------------------------------
310→
311→export async function runGraphScan(
312→  surreal: Surreal,
313→  workspaceRecord: RecordId<"workspace", string>,
314→  observerModel?: LanguageModel,
315→): Promise<GraphScanResult> {
316→  const result: GraphScanResult = {
317→    contradictions_found: 0,
318→    stale_blocked_found: 0,
319→    status_drift_found: 0,
320→    observations_created: 0,
321→  };
322→
323→  // Load existing observations for deduplication
324→  const existingObservations = await listWorkspaceOpenObservations({
325→    surreal,
326→    workspaceRecord,
327→    limit: 100,
328→  });
329→
330→  // 1. Detect decision-implementation contradictions
331→  const [decisions, completedTasks] = await Promise.all([
332→    queryConfirmedDecisions(surreal, workspaceRecord),
333→    queryCompletedTasks(surreal, workspaceRecord),
334→  ]);
335→
336→  const contradictions = detectContradictions(decisions, completedTasks);
337→  result.contradictions_found = contradictions.length;
338→
339→  for (const { decision, task } of contradictions) {
340→    // Entity-level dedup: check if observer already has an open observation on this decision
341→    const existingForDecision = await queryExistingObserverObservationsForEntity(
342→      surreal, workspaceRecord,
343→      decision.id as RecordId<string, string>,
344→    );
345→
346→    const observationText =
347→      `Contradiction detected: Decision "${decision.summary}" conflicts with completed task "${task.title}". ` +
348→      `The task appears to implement an approach that contradicts the confirmed decision.`;
349→
350→    if (existingForDecision.length > 0 || isAlreadyObserved(existingObservations, observationText)) {
351→      logInfo("observer.scan.dedup", "Skipping duplicate contradiction observation", {
352→        decisionId: decision.id.id,
353→        taskId: task.id.id,
354→      });
355→      continue;
356→    }
357→
358→    const now = new Date();
359→    await createObservation({
360→      surreal,
361→      workspaceRecord,
362→      text: observationText,
363→      severity: "conflict",
364→      sourceAgent: "observer_agent",
365→      observationType: "contradiction",
366→      now,
367→      relatedRecord: decision.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
368→    });
369→
370→    result.observations_created += 1;
371→  }
372→
373→  // 2. Detect stale blocked tasks
374→  const staleBlocked = await queryStaleBlockedTasks(surreal, workspaceRecord);
375→  result.stale_blocked_found = staleBlocked.length;
376→
377→  for (const task of staleBlocked) {
378→    // Entity-level dedup: check if observer already has an open observation on this task
379→    const existingForTask = await queryExistingObserverObservationsForEntity(
380→      surreal, workspaceRecord,
381→      task.id as RecordId<string, string>,
382→    );
383→
384→    const observationText =
385→      `Task blocked for ${task.daysBlocked} days: "${task.title}". ` +
386→      `This task has been blocked since ${new Date(task.updated_at).toISOString().slice(0, 10)} ` +
387→      `(exceeds the ${STALE_BLOCKED_THRESHOLD_DAYS}-day threshold).`;
388→
389→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText)) {
390→      logInfo("observer.scan.dedup", "Skipping duplicate stale-blocked observation", {
391→        taskId: task.id.id,
392→      });
393→      continue;
394→    }
395→
396→    const now = new Date();
397→    await createObservation({
398→      surreal,
399→      workspaceRecord,
400→      text: observationText,
401→      severity: "warning",
402→      sourceAgent: "observer_agent",
403→      observationType: "anomaly",
404→      now,
405→      relatedRecord: task.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
406→    });
407→
408→    result.observations_created += 1;
409→  }
410→
411→  // 3. Detect status drift (completed tasks with incomplete dependencies)
412→  const driftTasks = await queryStatusDriftTasks(surreal, workspaceRecord);
413→  result.status_drift_found = driftTasks.length;
414→
415→  for (const drift of driftTasks) {
416→    // Entity-level dedup
417→    const existingForTask = await queryExistingObserverObservationsForEntity(
418→      surreal, workspaceRecord,
419→      drift.id as RecordId<string, string>,
420→    );
421→
422→    const observationText =
423→      `Status drift detected: Task "${drift.title}" is marked as ${drift.status}, ` +
424→      `but its dependency "${drift.dependency.title}" is still ${drift.dependency.status}. ` +
425→      `A task should not be completed before its dependencies.`;
426→
427→    if (existingForTask.length > 0 || isAlreadyObserved(existingObservations, observationText)) {
428→      logInfo("observer.scan.dedup", "Skipping duplicate status-drift observation", {
429→        taskId: drift.id.id,
430→        depTaskId: drift.dependency.id.id,
431→      });
432→      continue;
433→    }
434→
435→    const now = new Date();
436→    await createObservation({
437→      surreal,
438→      workspaceRecord,
439→      text: observationText,
440→      severity: "warning",
441→      sourceAgent: "observer_agent",
442→      observationType: "anomaly",
443→      now,
444→      relatedRecord: drift.id as RecordId<"project" | "feature" | "task" | "decision" | "question", string>,
445→    });
446→
447→    result.observations_created += 1;
448→  }
449→
450→  // 4. LLM pattern synthesis (when model configured and anomalies exist)
451→  if (observerModel) {
452→    const anomalies: Anomaly[] = [];
453→
454→    for (const { decision, task } of contradictions) {
455→      anomalies.push({
456→        type: "contradiction",
457→        text: `Decision "${decision.summary}" conflicts with task "${task.title}"`,
458→        entityId: decision.id.id as string,
459→        entityTable: "decision",
460→      });
461→    }
462→    for (const task of staleBlocked) {
463→      anomalies.push({
464→        type: "stale_blocked",
465→        text: `Task "${task.title}" blocked for ${task.daysBlocked} days`,
466→        entityId: task.id.id as string,
467→        entityTable: "task",
468→      });
469→    }
470→    for (const drift of driftTasks) {
471→      anomalies.push({
472→        type: "status_drift",
473→        text: `Task "${drift.title}" completed but dependency "${drift.dependency.title}" is ${drift.dependency.status}`,
474→        entityId: drift.id.id as string,
475→        entityTable: "task",
476→      });
477→    }
478→
479→    if (anomalies.length > 0) {
480→      const patterns = await synthesizePatterns(observerModel, anomalies);
481→
482→      if (patterns) {
483→        for (const pattern of patterns) {
484→          // Dedup: check if a similar pattern observation already exists
485→          const patternText = `${pattern.pattern_name}: ${pattern.description}`;
486→          if (isAlreadyObserved(existingObservations, patternText)) {
487→            logInfo("observer.scan.synthesis_dedup", "Skipping duplicate pattern", {
488→              pattern: pattern.pattern_name,
489→            });
490→            continue;
491→          }
492→
493→          // Build related records from contributing entities
494→          const relatedRecords: ObserveTargetRecord[] = [];
495→          for (const ref of pattern.contributing_entities) {
496→            const parsed = parseEntityRef(ref);
497→            if (parsed) {
498→              relatedRecords.push(new RecordId(parsed.table, parsed.id) as ObserveTargetRecord);
499→            }
500→          }
501→
502→          const now = new Date();
503→          await createObservation({
504→            surreal,
505→            workspaceRecord,
506→            text: patternText,
507→            severity: pattern.severity,
508→            sourceAgent: "observer_agent",
509→            observationType: "pattern",
510→            now,
511→            relatedRecords: relatedRecords.length > 0 ? relatedRecords : undefined,
512→          });
513→
514→          result.observations_created += 1;
515→        }
516→
517→        logInfo("observer.scan.synthesis", "Pattern synthesis completed", {
518→          patternsFound: patterns.length,
519→        });
520→      } else {
521→        logInfo("observer.llm.fallback", "Pattern synthesis failed, anomalies reported individually", {
522→          anomalyCount: anomalies.length,
523→        });
524→      }
525→    }
526→  }
527→
528→  logInfo("observer.scan.completed", "Graph scan completed", {
529→    workspaceId: workspaceRecord.id,
530→    ...result,
531→  });
532→
533→  return result;
534→}
