238→// ---------------------------------------------------------------------------
239→// Observation peer review (deterministic + LLM)
240→// ---------------------------------------------------------------------------
241→
242→async function peerReviewObservation(input: ObserverAgentInput): Promise<ObserverAgentOutput> {
243→  const { surreal, workspaceRecord, entityId: observationId, entityBody: body, observerModel } = input;
244→  const observationRecord = new RecordId("observation", observationId);
245→
246→  const peerReviewSignals = await gatherPeerReviewSignals(surreal, workspaceRecord, body);
247→  const deterministicResult = compareObservationPeerReview(peerReviewSignals);
248→
249→  // LLM peer review when model available and observation has linked entities
250→  if (observerModel) {
251→    const linkedEntities = await loadObservationLinkedEntities(surreal, observationId);
252→
253→    if (linkedEntities.length > 0) {
254→      const llmVerdict = await generatePeerReviewVerdict(
