259→        linkedEntities,
260→      );
261→
262→      if (llmVerdict) {
263→        const severity = llmVerdict.verdict === "unsupported" ? "warning" as const
264→          : "info" as const;
265→
266→        const reviewResult: VerificationResult = {
267→          verdict: llmVerdict.verdict === "sound" ? "match" : llmVerdict.verdict === "unsupported" ? "mismatch" : "inconclusive",
268→          severity,
269→          verified: llmVerdict.verdict === "sound",
270→          text: llmVerdict.reasoning,
271→          source: "llm",
272→          confidence: llmVerdict.confidence,
273→          observationType: "validation",
274→        };
275→
276→        await persistObservation(surreal, workspaceRecord, observationRecord, reviewResult, "llm");
277→
278→        return {
279→          observations_created: 1,
280→          verdict: reviewResult.verdict,
281→          evidence: [reviewResult.text],
282→        };
283→      }
284→
285→      logInfo("observer.llm.fallback", "LLM peer review failed, using deterministic", { observationId });
286→    } else {
287→      logInfo("observer.llm.skip", "LLM peer review skipped: no linked entities", { observationId });
288→    }
289→  }
290→
291→  // Deterministic fallback
292→  await persistObservation(surreal, workspaceRecord, observationRecord, deterministicResult, "peer_review");
293→
294→  return {
295→    observations_created: 1,
296→    verdict: deterministicResult.verdict,
297→    evidence: [deterministicResult.text],
298→  };
299→}
