365→// ---------------------------------------------------------------------------
366→// DB helpers
367→// ---------------------------------------------------------------------------
368→
369→async function loadWorkspaceSkipSetting(
370→  surreal: Surreal,
371→  workspaceRecord: RecordId<"workspace", string>,
372→): Promise<boolean | undefined> {
