  id: RecordId<"decision">;
  summary: string;
  rationale?: string;
};

export type CompletedTask = {
  id: RecordId<"task">;
  title: string;
  description?: string;
};

export type StaleBlockedTask = {
  id: RecordId<"task">;
  title: string;
  description?: string;
  updated_at: string | Date;
  daysBlocked: number;
};

export type StatusDriftTask = {
  id: RecordId<"task">;
  title: string;
  status: string;
  dependency: {
    id: RecordId<"task">;
    title: string;
    status: string;
  };
